// ═══════════════════════════════════════════════════════
// DETERMINISTIC REPORT BUILDER
// All tables, verdict cards, and per-bidder summaries are
// built HERE from raw data — NOT by the LLM.
// The LLM only writes the 2-3 sentence narrative summary.
// This guarantees factual accuracy regardless of LLM output.
// ═══════════════════════════════════════════════════════

const tender = $('Fetch Tender Metadata').first().json;
const bidders = $('Fetch All Bidders').first().json;
const criteriaRaw = $('Fetch All Criteria').first().json;
const verdictsRaw = $('Fetch All Verdicts').first().json;
const evidenceRaw = $('Fetch All Evidence').first().json;

const criteria = Array.isArray(criteriaRaw) ? criteriaRaw : (criteriaRaw.criteria || []);
const verdicts = Array.isArray(verdictsRaw) ? verdictsRaw : (verdictsRaw.verdicts || []);
const evidence = Array.isArray(evidenceRaw) ? evidenceRaw : (evidenceRaw.evidence || []);
const bidderList = Array.isArray(bidders) ? bidders : (bidders.bidders || []);

// Build verdict lookup: bidder_id + criterion_id → verdict
const verdictMap = {};
for (const v of verdicts) {
  verdictMap[`${v.bidder_id}__${v.criterion_id}`] = v;
}

// Build evidence lookup: bidder_id + criterion_id → evidence
const evidenceMap = {};
for (const e of evidence) {
  evidenceMap[`${e.bidder_id}__${e.criterion_id}`] = e;
}

// ── Build per-bidder verdict cards (deterministic) ──
const bidderCards = bidderList.map(bidder => {
  const criterionResults = criteria.map(criterion => {
    const key = `${bidder.id}__${criterion.id}`;
    const v = verdictMap[key];
    const e = evidenceMap[key];
    return {
      criterion_id: criterion.criterion_id,
      criterion_name: criterion.name,
      criterion_type: criterion.type,
      mandatory: criterion.mandatory,
      threshold_value: criterion.threshold_value,
      threshold_unit: criterion.threshold_unit,
      verdict: v?.verdict || 'PENDING',
      verdict_reason: v?.reason || 'Not yet evaluated',
      verdict_confidence: v?.verdict_confidence || null,
      verdict_method: v?.verdict_method || null,
      officer_override: v?.officer_override || null,
      officer_override_reason: v?.officer_override_reason || null,
      extracted_value: e?.value || null,
      quoted_text: e?.quoted_text || null,
      source_page: e?.source_page || null
    };
  });

  // Overall bidder verdict: ELIGIBLE only if ALL mandatory criteria pass
  const mandatoryCriteria = criterionResults.filter(r => r.mandatory === true);
  const allMandatoryPass = mandatoryCriteria.every(r => r.verdict === 'ELIGIBLE');
  const anyManualPending = criterionResults.some(r => r.verdict === 'MANUAL_REVIEW');
  const failedCriteria = criterionResults.filter(r => r.verdict === 'INELIGIBLE').map(r => r.criterion_id);

  let overallVerdict;
  if (anyManualPending) overallVerdict = 'PENDING_REVIEW';
  else if (allMandatoryPass) overallVerdict = 'ELIGIBLE';
  else overallVerdict = 'INELIGIBLE';

  return {
    bidder_id: bidder.id,
    bidder_name: bidder.name,
    bidder_city: bidder.city || '',
    jv_flag: bidder.jv_flag || false,
    submission_time: bidder.submission_time || null,
    overall_verdict: overallVerdict,
    failed_criteria: failedCriteria,
    pending_review_count: criterionResults.filter(r => r.verdict === 'MANUAL_REVIEW').length,
    criterion_results: criterionResults
  };
});

// ── Master eligibility matrix (for the summary table) ──
const eligible = bidderCards.filter(b => b.overall_verdict === 'ELIGIBLE');
const ineligible = bidderCards.filter(b => b.overall_verdict === 'INELIGIBLE');
const pending = bidderCards.filter(b => b.overall_verdict === 'PENDING_REVIEW');

// ── Build a compact narrative prompt for Mistral ──
// Only the SUMMARY paragraph — tables come from deterministic code
const narrativePromptData = {
  tender_reference: tender.reference_number || tender.id,
  tender_title: tender.title,
  total_bidders: bidderList.length,
  eligible_count: eligible.length,
  ineligible_count: ineligible.length,
  pending_count: pending.length,
  eligible_bidder_names: eligible.map(b => b.bidder_name),
  ineligible_summary: ineligible.map(b => ({
    name: b.bidder_name,
    failed: b.failed_criteria
  }))
};

return [{
  json: {
    tender,
    bidderCards,
    criteria,
    eligible,
    ineligible,
    pending,
    narrativePromptData,
    include_audit_trail: $('Webhook Trigger').first().json.include_audit_trail || false,
    generated_at: new Date().toISOString()
  }
}];

