// Parse LLM narrative. On failure, use a safe fallback — never block report generation.
const llmResponse = $input.first().json;
const reportData = $('Build Report Data (Deterministic)').first().json;

let raw = llmResponse.choices?.[0]?.message?.content || '';
raw = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();

const objStart = raw.indexOf('{');
const objEnd = raw.lastIndexOf('}');

let narrative = {
  summary: `Technical bid evaluation for Tender ${reportData.tender?.reference_number || reportData.tender?.id} has been completed. ${reportData.eligible.length} bidder(s) qualified and ${reportData.ineligible.length} bidder(s) were found ineligible.`,
  recommendation: 'Financial bids of eligible bidders may be opened as per schedule. Rejection letters to be issued to ineligible bidders with specific criterion references.'
};

if (objStart !== -1 && objEnd !== -1) {
  try {
    const parsed = JSON.parse(raw.substring(objStart, objEnd + 1));
    if (parsed.summary) narrative.summary = parsed.summary;
    if (parsed.recommendation) narrative.recommendation = parsed.recommendation;
  } catch (e) {
    // Use fallback narrative — safe default
    console.log('LLM narrative parse failed, using fallback:', e.message);
  }
}

// Merge narrative into report data
return [{
  json: {
    ...reportData,
    narrative
  }
}];

// Build the complete HTML report.
// Uses only inline CSS — WeasyPrint has limited CSS3 support.
// No flexbox, no grid, no external fonts, no relative units in critical layout.
// All tables use border-collapse with explicit border attributes.

const d = $input.first().json;
const { tender, bidderCards, criteria, eligible, ineligible, pending, narrative, generated_at } = d;

const NAVY = '#1B3A6B';
const GREEN = '#1A5C35';
const GREEN_LIGHT = '#D4F0DC';
const RED = '#7A1F1F';
const RED_LIGHT = '#FAE0E0';
const AMBER = '#7A4E00';
const AMBER_LIGHT = '#FFF3CD';
const GRAY = '#595959';
const BORDER = '#CCCCCC';

function verdictBadge(verdict) {
  const map = {
    ELIGIBLE:      { bg: GREEN_LIGHT, color: GREEN,  label: 'ELIGIBLE' },
    INELIGIBLE:    { bg: RED_LIGHT,   color: RED,    label: 'INELIGIBLE' },
    MANUAL_REVIEW: { bg: AMBER_LIGHT, color: AMBER,  label: 'REVIEW' },
    PENDING_REVIEW:{ bg: AMBER_LIGHT, color: AMBER,  label: 'PENDING' },
    PENDING:       { bg: '#F2F4F7',   color: GRAY,   label: 'PENDING' }
  };
  const s = map[verdict] || { bg: '#F2F4F7', color: GRAY, label: verdict };
  return `<span style="background:${s.bg};color:${s.color};font-weight:bold;padding:2px 8px;border-radius:3px;font-size:11px;font-family:Arial,sans-serif">${s.label}</span>`;
}

function th(text, width) {
  return `<th style="background:${NAVY};color:#ffffff;padding:8px 10px;text-align:left;font-family:Arial,sans-serif;font-size:12px;${width ? 'width:'+width+';' : ''}">${text}</th>`;
}
function td(text, extra) {
  return `<td style="padding:7px 10px;border-bottom:1px solid ${BORDER};font-family:Arial,sans-serif;font-size:12px;vertical-align:top;${extra||''}">${text||'—'}</td>`;
}
function tdCenter(text) {
  return `<td style="padding:7px 10px;border-bottom:1px solid ${BORDER};font-family:Arial,sans-serif;font-size:12px;text-align:center;vertical-align:middle;">${text||'—'}</td>`;
}

// ── Section: Master Eligibility Matrix ──
let matrixRows = '';
for (const bidder of bidderCards) {
  let criteriaVerdicts = '';
  for (const cr of bidder.criterion_results) {
    criteriaVerdicts += tdCenter(verdictBadge(cr.verdict));
  }
  matrixRows += `<tr>${td(bidder.bidder_name, 'font-weight:bold')}${criteriaVerdicts}${tdCenter(verdictBadge(bidder.overall_verdict))}</tr>`;
}

let matrixHeaders = th('Bidder', '180px');
for (const cr of criteria) {
  matrixHeaders += th(cr.criterion_id + '<br><span style="font-size:10px;font-weight:normal">' + cr.name + '</span>', '110px');
}
matrixHeaders += th('Overall', '100px');

const masterMatrix = `
<h2 style="color:${NAVY};font-family:Arial,sans-serif;font-size:15px;border-bottom:2px solid ${NAVY};padding-bottom:6px;margin-top:28px">Master Eligibility Matrix</h2>
<table width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse;border:1px solid ${BORDER};margin-top:10px">
  <thead><tr>${matrixHeaders}</tr></thead>
  <tbody>${matrixRows}</tbody>
</table>`;

// ── Section: Per-Bidder Verdict Cards ──
let bidderSections = '';
for (const bidder of bidderCards) {
  const overallColor = bidder.overall_verdict === 'ELIGIBLE' ? GREEN : bidder.overall_verdict === 'INELIGIBLE' ? RED : AMBER;
  const overallBg = bidder.overall_verdict === 'ELIGIBLE' ? GREEN_LIGHT : bidder.overall_verdict === 'INELIGIBLE' ? RED_LIGHT : AMBER_LIGHT;

  let criterionRows = '';
  for (const cr of bidder.criterion_results) {
    const override = cr.officer_override ? `<br><span style="font-size:10px;color:${AMBER}">Officer override: ${cr.officer_override} — ${cr.officer_override_reason || ''}</span>` : '';
    criterionRows += `<tr>
      ${td(cr.criterion_id)}
      ${td(cr.criterion_name, 'font-weight:bold')}
      ${td(cr.extracted_value !== null ? String(cr.extracted_value) : '—')}
      ${td(cr.threshold_value !== null ? `${cr.threshold_value} ${cr.threshold_unit||''}` : '—')}
      ${td(cr.quoted_text ? `<em style="font-size:11px;color:${GRAY}">&ldquo;${cr.quoted_text}&rdquo;</em><br>Page ${cr.source_page||'?'}` : '—')}
      ${tdCenter(verdictBadge(cr.verdict) + override)}
    </tr>`;
  }

  bidderSections += `
<div style="margin-top:24px;border:1px solid ${BORDER};border-radius:4px;overflow:hidden;page-break-inside:avoid">
  <div style="background:${overallBg};padding:12px 16px;border-bottom:2px solid ${overallColor}">
    <span style="font-family:Arial,sans-serif;font-size:14px;font-weight:bold;color:${overallColor}">${bidder.bidder_name}</span>
    ${bidder.jv_flag ? '<span style="font-size:11px;color:#5B2D8E;margin-left:10px">[Joint Venture]</span>' : ''}
    <span style="float:right">${verdictBadge(bidder.overall_verdict)}</span>
  </div>
  <table width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse">
    <thead><tr>${th('C#','40px')}${th('Criterion')}${th('Extracted Value','110px')}${th('Threshold','110px')}${th('Source Evidence')}${th('Verdict','100px')}</tr></thead>
    <tbody>${criterionRows}</tbody>
  </table>
</div>`;
}

// ── Final HTML assembly ──
const html = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Evaluation Report — ${tender.reference_number || tender.id}</title>
<style>
  @page { margin: 2cm; }
  body { font-family: Arial, sans-serif; font-size: 12px; color: #1A1A1A; }
  h1 { font-size: 18px; color: ${NAVY}; margin-bottom: 4px; }
  h2 { font-size: 15px; color: ${NAVY}; }
  table { border-collapse: collapse; width: 100%; }
  th { background: ${NAVY}; color: #fff; text-align: left; padding: 8px 10px; }
  td { padding: 7px 10px; border-bottom: 1px solid ${BORDER}; vertical-align: top; }
</style>
</head>
<body>

<!-- LETTERHEAD -->
<table width="100%" cellpadding="0" cellspacing="0" style="margin-bottom:24px">
  <tr>
    <td style="text-align:center;padding:16px;background:${NAVY};color:#ffffff">
      <div style="font-size:13px;font-weight:bold">GOVERNMENT OF INDIA — MINISTRY OF HOME AFFAIRS</div>
      <div style="font-size:16px;font-weight:bold;margin-top:4px">CENTRAL RESERVE POLICE FORCE (CRPF)</div>
      <div style="font-size:11px;margin-top:2px">TECHNICAL BID EVALUATION REPORT — AI-ASSISTED</div>
    </td>
  </tr>
</table>

<!-- TENDER DETAILS -->
<table width="100%" cellpadding="0" cellspacing="0" style="border:1px solid ${BORDER};margin-bottom:20px">
  <tr><td style="width:200px;font-weight:bold;padding:7px 12px;background:#F2F4F7;border-bottom:1px solid ${BORDER}">Tender Reference</td><td style="padding:7px 12px;border-bottom:1px solid ${BORDER}">${tender.reference_number || '—'}</td><td style="width:200px;font-weight:bold;padding:7px 12px;background:#F2F4F7;border-bottom:1px solid ${BORDER}">Date Generated</td><td style="padding:7px 12px;border-bottom:1px solid ${BORDER}">${new Date(generated_at).toLocaleDateString('en-IN', {day:'2-digit',month:'long',year:'numeric'})}</td></tr>
  <tr><td style="font-weight:bold;padding:7px 12px;background:#F2F4F7">Name of Work</td><td colspan="3" style="padding:7px 12px">${tender.title || '—'}</td></tr>
</table>

<!-- NARRATIVE SUMMARY -->
<h2 style="color:${NAVY};font-size:15px;border-bottom:2px solid ${NAVY};padding-bottom:6px">Evaluation Summary</h2>
<p style="line-height:1.7;margin:10px 0">${narrative.summary}</p>
<p style="line-height:1.7;margin:10px 0"><strong>Recommendation:</strong> ${narrative.recommendation}</p>

${masterMatrix}

<!-- OUTCOME TABLE -->
<h2 style="color:${NAVY};font-size:15px;border-bottom:2px solid ${NAVY};padding-bottom:6px;margin-top:28px">Final Outcome</h2>
<table width="100%" cellpadding="0" cellspacing="0" style="border:1px solid ${BORDER}">
  <thead><tr>${th('Bidder')}${th('Overall')}${th('Failed Criteria')}${th('Action Required')}</tr></thead>
  <tbody>
    ${bidderCards.map(b => `<tr>
      ${td(b.bidder_name, 'font-weight:bold')}
      ${tdCenter(verdictBadge(b.overall_verdict))}
      ${td(b.failed_criteria.length ? b.failed_criteria.join(', ') : '—')}
      ${td(b.overall_verdict === 'ELIGIBLE' ? 'Open financial bid' : b.overall_verdict === 'INELIGIBLE' ? 'Issue rejection letter' : 'Officer review pending')}
    </tr>`).join('')}
  </tbody>
</table>

<!-- PER-BIDDER CARDS -->
<h2 style="color:${NAVY};font-size:15px;border-bottom:2px solid ${NAVY};padding-bottom:6px;margin-top:28px">Per-Bidder Criterion Detail</h2>
${bidderSections}

<!-- FOOTER -->
<div style="margin-top:48px;border-top:2px solid ${NAVY};padding-top:16px">
  <table width="100%" cellpadding="0" cellspacing="0">
    <tr>
      <td style="width:50%">
        <div style="font-size:11px;color:${GRAY}">Generated by SmartTender AI — ${new Date(generated_at).toISOString()}</div>
        <div style="font-size:11px;color:${GRAY}">All verdicts subject to officer confirmation. AI is a decision-support tool.</div>
      </td>
      <td style="width:50%;text-align:right">
        <div style="font-size:12px;font-weight:bold">Procurement Officer Signature</div>
        <div style="margin-top:32px;border-top:1px solid #000;width:200px;float:right;text-align:center;padding-top:4px;font-size:11px">Name / Designation / Date</div>
      </td>
    </tr>
  </table>
</div>

</body>
</html>`;

return [{
  json: {
    tender_id: $('Webhook Trigger').first().json.tender_id,
    html_content: html,
    report_metadata: {
      tender_reference: tender.reference_number || tender.id,
      generated_at,
      total_bidders: bidderCards.length,
      eligible_count: eligible.length,
      ineligible_count: ineligible.length,
      pending_count: pending.length
    }
  }
}];
